import java.util.*;

class Graph {
    private final Map<String, List<Edge>> adjacencyList = new HashMap<>();

    public void addVertex(String label) {
        adjacencyList.putIfAbsent(label, new ArrayList<>());
    }

    public void addEdge(String from, String to, int trafficDensity) {
        adjacencyList.get(from).add(new Edge(to, trafficDensity));
        adjacencyList.get(to).add(new Edge(from, trafficDensity)); // Assuming undirected graph
    }

    public Map<String, List<Edge>> getAdjacencyList() {
        return adjacencyList;
    }

    static class Edge {
        String destination;
        int trafficDensity;

        Edge(String destination, int trafficDensity) {
            this.destination = destination;
            this.trafficDensity = trafficDensity;
        }
    }
}

public class TrafficOptimizer {
    public static List<String> trafficOptimizer(Graph graph, String start, String end) {
        PriorityQueue<PathNode> queue = new PriorityQueue<>(Comparator.comparingInt(node -> node.trafficDensity));
        Map<String, Integer> visited = new HashMap<>();
        queue.add(new PathNode(start, 0, new ArrayList<>()));

        while (!queue.isEmpty()) {
            PathNode current = queue.poll();
            if (visited.containsKey(current.vertex) && visited.get(current.vertex) <= current.trafficDensity) {
                continue;
            }
            visited.put(current.vertex, current.trafficDensity);
            current.path.add(current.vertex);

            if (current.vertex.equals(end)) {
                return current.path;
            }

            for (Graph.Edge edge : graph.getAdjacencyList().get(current.vertex)) {
                if (!visited.containsKey(edge.destination) || visited.get(edge.destination) > current.trafficDensity + edge.trafficDensity) {
                    List<String> newPath = new ArrayList<>(current.path);
                    queue.add(new PathNode(edge.destination, current.trafficDensity + edge.trafficDensity, newPath));
                }
            }
        }
        return new ArrayList<>(); // Return empty list if no path found
    }

    static class PathNode {
        String vertex;
        int trafficDensity;
        List<String> path;

        PathNode(String vertex, int trafficDensity, List<String> path) {
            this.vertex = vertex;
            this.trafficDensity = trafficDensity;
            this.path = path;
        }
    }
}

