    private List<LoginRecord> loginHistory = new ArrayList<>();

    public void processLoginHistory(JSONObject jsonInput) {
        String operation = jsonInput.getString("operation");

        switch (operation) {
            case "add":
                JSONObject addData = jsonInput.getJSONObject("data");
                String userId = addData.getString("userId");
                String timestamp = addData.getString("timestamp");
                loginHistory.add(new LoginRecord(userId, timestamp));
                break;

            case "retrieve":
                String retrieveUserId = jsonInput.getJSONObject("data").getString("userId");
                retrieveLoginData(retrieveUserId);
                break;

            case "delete":
                String deleteUserId = jsonInput.getJSONObject("data").getString("userId");
                deleteLoginData(deleteUserId);
                break;

            default:
                throw new IllegalArgumentException("Invalid operation type.");
        }
    }

    private void retrieveLoginData(String userId) {
        for (LoginRecord record : loginHistory) {
            if (record.userId.equals(userId)) {
                System.out.println("User ID: " + record.userId + ", Timestamp: " + record.timestamp);
            }
        }
    }

    private void deleteLoginData(String userId) {
        Iterator<LoginRecord> iterator = loginHistory.iterator();
        while (iterator.hasNext()) {
            LoginRecord record = iterator.next();
            if (record.userId.equals(userId)) {
                iterator.remove();
            }
        }
