struct PermissionNode {
    std::string permission;
    std::map<std::string, PermissionNode> children;
};

class PermissionTree {
public:
    PermissionNode root;

    PermissionTree(const std::string& rootPermission) {
        root.permission = rootPermission;
    }

    void addPermission(const std::vector<std::string>& path, const std::string& newPermission) {
        PermissionNode* current = &root;
        for (const std::string& node : path) {
            current = &current->children[node];
        }
        current->children[newPermission] = PermissionNode{newPermission};
    }

    void updatePermission(const std::vector<std::string>& path, const std::string& updatedPermission) {
        PermissionNode* current = &root;
        for (const std::string& node : path) {
            current = &current->children[node];
        }
        current->permission = updatedPermission;
    }

    void removePermission(const std::vector<std::string>& path) {
        PermissionNode* current = &root;
        for (size_t i = 0; i < path.size() - 1; i++) {
            current = &current->children[path[i]];
        }
        current->children.erase(path.back());
    }
};

void managePermissions(PermissionTree& tree, const std::string& operation, const std::vector<std::string>& path, const std::string& permission = "") {
    if (operation == "add") {
        tree.addPermission(path, permission);
    } else if (operation == "update") {
        tree.updatePermission(path, permission);
    } else if (operation == "remove") {
        tree.removePermission(path);
    }
}

fn process_grid_operations(mut matrix: Vec<Vec<i32>>, operations: Vec<String>) -> Vec<Vec<i32>> {
    for operation in operations {
        match operation.as_str() {
            "rotate" => {
                let n = matrix.len();
                let mut rotated = vec![vec![0; n]; n];
                for i in 0..n {
                    for j in 0..n {
                        rotated[j][n - 1 - i] = matrix[i][j];
                    }
                }
                matrix = rotated;
            }
            "flip" => {
                matrix = matrix.into_iter().map(|row| row.into_iter().rev().collect()).collect();
            }
            "invert" => {
                matrix = matrix
                    .into_iter()
                    .map(|row| row.into_iter().map(|x| if x == 0 { 1 } else { 0 }).collect())
                    .collect();
            }
            _ => {}
        }
    }
    matrix
}

