public class MatrixTransformer {
    public static int[][] transformMatrix(int[][] matrix, String operationMode) {
        int rows = matrix.length, cols = matrix[0].length;
        int[][] result;

        switch (operationMode) {
            case "rotate_left":
                result = new int[cols][rows];
                for (int i = 0; i < rows; i++)
                    for (int j = 0; j < cols; j++)
                        result[cols - j - 1][i] = matrix[i][j];
                break;

            case "rotate_right":
                result = new int[cols][rows];
                for (int i = 0; i < rows; i++)
                    for (int j = 0; j < cols; j++)
                        result[j][rows - i - 1] = matrix[i][j];
                break;

            case "flip_vertical":
                result = new int[rows][cols];
                for (int i = 0; i < rows; i++)
                    for (int j = 0; j < cols; j++)
                        result[rows - i - 1][j] = matrix[i][j];
                break;

            case "flip_horizontal":
                result = new int[rows][cols];
                for (int i = 0; i < rows; i++)
                    for (int j = 0; j < cols; j++)
                        result[i][cols - j - 1] = matrix[i][j];
                break;

            default:
                throw new IllegalArgumentException("Invalid operation mode");
        }

        return result;
    }
}

